const $=s=>document.querySelector(s);async function data(){return fetch('/products.json').then(r=>r.json())}if($('#runtime-form')){$('#runtime-form').addEventListener('submit',e=>{e.preventDefault();const f=new FormData(e.target);const h=(+f.get('capacity')*.85)/(+f.get('watts')*(+f.get('duty')/100));$('#runtime-output').textContent=isFinite(h)?h.toFixed(1)+' estimated hours':'Enter valid numbers';});}if($('#compare-app')){data().then(ps=>{const opts=ps.map(p=>'<option value="'+p.slug+'">'+p.brand+' '+p.name+'</option>').join('');$('#compare-app').innerHTML='<label>Model A<select id="a">'+opts+'</select></label><label>Model B<select id="b">'+opts+'</select></label><div id="cmp"></div>';const draw=()=>{const a=ps.find(p=>p.slug==$('#a').value),b=ps.find(p=>p.slug==$('#b').value);$('#cmp').innerHTML='<table><tr><th>Metric</th><th>'+a.brand+' '+a.name+'</th><th>'+b.brand+' '+b.name+'</th></tr>'+['capacityWh','chemistry','acOutputW','solarInputW','weightLb','lowPrice'].map(k=>'<tr><td>'+k+'</td><td>'+a[k]+'</td><td>'+b[k]+'</td></tr>').join('')+'</table>';};$('#b').selectedIndex=Math.min(1,ps.length-1);$('#a').onchange=$('#b').onchange=draw;draw();});}